import{_ as e,o as i,c as a,e as d}from"./app-25fa875f.js";const l={},o=d('<h1 id="solidity-units-and-globally-available-variables" tabindex="-1"><a class="header-anchor" href="#solidity-units-and-globally-available-variables" aria-hidden="true">#</a> Solidity - Units and Globally Available Variables</h1><p>Created by : Mr Dk.</p><p>2020 / 02 / 25 22:42</p><p>Ningbo, Zhejiang, China</p><hr><h2 id="ether-units" tabindex="-1"><a class="header-anchor" href="#ether-units" aria-hidden="true">#</a> Ether Units</h2><p>最小单位 - <code>wei</code></p><ul><li><code>wei</code> - 最小单位，也是单位缺省时的默认单位</li><li><code>szabo</code> - <code>10^12 wei</code></li><li><code>finney</code> - <code>10^3 szabo</code></li><li><code>ether</code> - <code>10^3 finney</code></li></ul><h2 id="time-units" tabindex="-1"><a class="header-anchor" href="#time-units" aria-hidden="true">#</a> Time Units</h2><ul><li><code>seconds</code></li><li><code>minutes</code></li><li><code>hours</code></li><li><code>days</code></li><li><code>weeks</code></li><li><code>years</code></li></ul><h2 id="special-variables-and-functions" tabindex="-1"><a class="header-anchor" href="#special-variables-and-functions" aria-hidden="true">#</a> Special Variables and Functions</h2><h3 id="block-and-transaction-properties" tabindex="-1"><a class="header-anchor" href="#block-and-transaction-properties" aria-hidden="true">#</a> Block and Transaction Properties</h3><ul><li><code>block.blockhash(uint blockNumber) returns (bytes32)</code> - 256 个最近的区块 hash</li><li><code>address block.coinbase</code> - 目前区块矿工地址</li><li><code>unit block.difficulty</code> - 目前区块的难度</li><li><code>uint block.gaslimit</code> - 目前区块的 gaslimit</li><li><code>uint block.number</code> - 目前区块的 number</li><li><code>uint block.timestamp</code> - 目前区块的 Unix 时间戳</li><li><code>bytes msg.data</code> - 完整的 calldata</li><li><code>uint msg.gas</code> - 剩余的 gas</li><li><code>address msg.sender</code> - 目前调用的发送者</li><li><code>bytes4 msg.sig</code> - Calldata 的前四个字节 (函数标识符)</li><li><code>uint msg.value</code> - 随着 message 发送的 wei</li><li><code>uint now</code> - 目前区块的 Unix 时间戳</li><li><code>uint tx.gasprice</code> - 交易的 gas price</li><li><code>address tx.origin</code> - 交易的发起方</li></ul><p><code>msg</code> 在每次 external function call 中可能都是不一样的。</p><p>处于安全性的考虑，不要使用区块的时间戳或者 hash 等作为随机数的生成源 - 因为这些数据可以被矿工操控。</p><h3 id="error-handling" tabindex="-1"><a class="header-anchor" href="#error-handling" aria-hidden="true">#</a> Error Handling</h3><ul><li><code>assert(bool condition)</code> - 如果条件不满足，就抛出；用于内部错误</li><li><code>require(bool condition)</code> - 如果条件不满足，就抛出；用于外部输入错误</li><li><code>revert()</code> - 中止执行，回滚状态改变</li></ul><h2 id="mathematical-and-cryptographic-functions" tabindex="-1"><a class="header-anchor" href="#mathematical-and-cryptographic-functions" aria-hidden="true">#</a> Mathematical and Cryptographic Functions</h2><h2 id="address-related" tabindex="-1"><a class="header-anchor" href="#address-related" aria-hidden="true">#</a> Address Related</h2><ul><li><code>&lt;address&gt;.balance (uint256)</code> - 地址中的余额 (wei 为单位)</li><li><code>&lt;address&gt;.transfer(uint256 amount)</code> - 向指定地址转账，如果失败就抛出异常</li><li><code>&lt;address&gt;.send(uint256 amount) returns (bool)</code> - 向指定地址转账，如果失败则返回 <code>false</code></li><li><code>&lt;address&gt;.call(...) returns (bool)</code></li><li><code>&lt;address&gt;.callcode(...) returns (bool)</code></li><li><code>&lt;address&gt;.delegatecall(...) returns (bool)</code></li></ul><h2 id="contract-related" tabindex="-1"><a class="header-anchor" href="#contract-related" aria-hidden="true">#</a> Contract Related</h2><ul><li><code>this</code> - 当前 contract</li><li><code>selfdestruct(address recipient)</code> - 自毁，将资金转向指定地址</li><li><code>suicide(address recipient)</code> - 同上</li></ul><hr>',23),c=[o];function t(r,s){return i(),a("div",null,c)}const h=e(l,[["render",t],["__file","Solidity Units and Globally Variables.html.vue"]]);export{h as default};
